import{_ as e,o as d,c as l,ag as a}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Chmod 别名 | Dotfiles (ZH)","titleTemplate":":title","description":"使用 chmod 别名简化文件和目录权限管理。常见权限模式（如 755、644 等）的快捷方式。","frontmatter":{"title":"Chmod 别名 | Dotfiles","description":"使用 chmod 别名简化文件和目录权限管理。常见权限模式（如 755、644 等）的快捷方式。","lang":"zh-CN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Chmod 别名 preview","canonical":"/zh/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Chmod 别名","pageType":"docs","schemaType":"WebPage","metaTitle":"Chmod 别名 - Dotfiles (CN)","permalink":"/zh/aliases/chmod/","sidebar":true,"meta":[{"name":"keywords","content":"chmod 别名, 文件权限, shell 快捷方式, dotfiles, unix 权限"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Chmod 别名 - Dotfiles"},{"name":"twitter:description","content":"使用 chmod 别名简化文件和目录权限管理。"},{"name":"og:title","content":"Chmod 别名 - Dotfiles"},{"name":"og:description","content":"使用 chmod 别名简化文件和目录权限管理。"},{"name":"og:image:alt","content":"Dotfiles - 为你的 Shell 生活精心设计"},{"name":"og:locale","content":"zh_CN"}]},"headers":[],"relativePath":"zh/aliases/chmod/index.md","filePath":"zh/aliases/chmod/index.md","lastUpdated":1773010926000}'),o={name:"zh/aliases/chmod/index.md"};function i(c,t,r,s,n,h){return d(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="chmod-别名" tabindex="-1">Chmod 别名 <a class="header-anchor" href="#chmod-别名" aria-label="Permalink to &quot;Chmod 别名&quot;">​</a></h1><p>管理文件和目录权限的快捷方式。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>chmod 别名提供了从命令行管理文件和目录权限的简化方式。无需记住数字权限代码，使用直观的别名如 <code>chmod_755</code> 或 <code>chmod_u+x</code> 快速设置所需的访问模式。</p><p>这些别名定义在 <code>chmod.aliases.sh</code> 中，由 chezmoi 自动加载。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><h3 id="常用权限别名" tabindex="-1">常用权限别名 <a class="header-anchor" href="#常用权限别名" aria-label="Permalink to &quot;常用权限别名&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">权限</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_000</code></td><td style="text-align:left;"><code>----------</code></td><td style="text-align:left;">任何人都没有权限</td></tr><tr><td style="text-align:left;"><code>chmod_400</code></td><td style="text-align:left;"><code>r--------</code></td><td style="text-align:left;">所有者只读</td></tr><tr><td style="text-align:left;"><code>chmod_444</code></td><td style="text-align:left;"><code>r--r--r--</code></td><td style="text-align:left;">所有人只读</td></tr><tr><td style="text-align:left;"><code>chmod_600</code></td><td style="text-align:left;"><code>rw-------</code></td><td style="text-align:left;">所有者读写</td></tr><tr><td style="text-align:left;"><code>chmod_644</code></td><td style="text-align:left;"><code>rw-r--r--</code></td><td style="text-align:left;">所有者读写，其他人只读</td></tr><tr><td style="text-align:left;"><code>chmod_666</code></td><td style="text-align:left;"><code>rw-rw-rw-</code></td><td style="text-align:left;">所有人读写</td></tr><tr><td style="text-align:left;"><code>chmod_755</code></td><td style="text-align:left;"><code>rwxr-xr-x</code></td><td style="text-align:left;">所有者完全权限，其他人读执行</td></tr><tr><td style="text-align:left;"><code>chmod_764</code></td><td style="text-align:left;"><code>rwxrw-r--</code></td><td style="text-align:left;">所有者完全权限，组读写</td></tr><tr><td style="text-align:left;"><code>chmod_777</code></td><td style="text-align:left;"><code>rwxrwxrwx</code></td><td style="text-align:left;">所有人完全权限</td></tr></tbody></table><h3 id="所有者权限别名" tabindex="-1">所有者权限别名 <a class="header-anchor" href="#所有者权限别名" aria-label="Permalink to &quot;所有者权限别名&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_u+x</code></td><td style="text-align:left;">为所有者添加执行权限</td></tr><tr><td style="text-align:left;"><code>chmod_u-x</code></td><td style="text-align:left;">移除所有者的执行权限</td></tr><tr><td style="text-align:left;"><code>chmod_u+w</code></td><td style="text-align:left;">为所有者添加写入权限</td></tr><tr><td style="text-align:left;"><code>chmod_u-w</code></td><td style="text-align:left;">移除所有者的写入权限</td></tr><tr><td style="text-align:left;"><code>chmod_u+r</code></td><td style="text-align:left;">为所有者添加读取权限</td></tr><tr><td style="text-align:left;"><code>chmod_u-r</code></td><td style="text-align:left;">移除所有者的读取权限</td></tr></tbody></table><h3 id="组权限别名" tabindex="-1">组权限别名 <a class="header-anchor" href="#组权限别名" aria-label="Permalink to &quot;组权限别名&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_g+x</code></td><td style="text-align:left;">为组添加执行权限</td></tr><tr><td style="text-align:left;"><code>chmod_g-x</code></td><td style="text-align:left;">移除组的执行权限</td></tr><tr><td style="text-align:left;"><code>chmod_g+w</code></td><td style="text-align:left;">为组添加写入权限</td></tr><tr><td style="text-align:left;"><code>chmod_g-w</code></td><td style="text-align:left;">移除组的写入权限</td></tr><tr><td style="text-align:left;"><code>chmod_g+r</code></td><td style="text-align:left;">为组添加读取权限</td></tr><tr><td style="text-align:left;"><code>chmod_g-r</code></td><td style="text-align:left;">移除组的读取权限</td></tr></tbody></table><h3 id="其他人权限别名" tabindex="-1">其他人权限别名 <a class="header-anchor" href="#其他人权限别名" aria-label="Permalink to &quot;其他人权限别名&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_o+x</code></td><td style="text-align:left;">为其他人添加执行权限</td></tr><tr><td style="text-align:left;"><code>chmod_o-x</code></td><td style="text-align:left;">移除其他人的执行权限</td></tr><tr><td style="text-align:left;"><code>chmod_o+w</code></td><td style="text-align:left;">为其他人添加写入权限</td></tr><tr><td style="text-align:left;"><code>chmod_o-w</code></td><td style="text-align:left;">移除其他人的写入权限</td></tr><tr><td style="text-align:left;"><code>chmod_o+r</code></td><td style="text-align:left;">为其他人添加读取权限</td></tr><tr><td style="text-align:left;"><code>chmod_o-r</code></td><td style="text-align:left;">移除其他人的读取权限</td></tr></tbody></table><h3 id="文件类型别名" tabindex="-1">文件类型别名 <a class="header-anchor" href="#文件类型别名" aria-label="Permalink to &quot;文件类型别名&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_755d</code></td><td style="text-align:left;">将所有目录权限设置为 <code>rwxr-xr-x</code></td></tr><tr><td style="text-align:left;"><code>chmod_644f</code></td><td style="text-align:left;">将所有文件权限设置为 <code>rw-r--r--</code></td></tr></tbody></table><h3 id="递归权限函数" tabindex="-1">递归权限函数 <a class="header-anchor" href="#递归权限函数" aria-label="Permalink to &quot;递归权限函数&quot;">​</a></h3><p><code>change_permission</code> 函数递归应用权限并带有确认提示：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">change_permission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span></span></code></pre></div>',19)])])}const f=e(o,[["render",i]]);export{g as __pageData,f as default};
